        }

        // Tráfico (capa 4)
        for (_entity, (pos, renderable)) in world.query::<(&Position, &Renderable)>().iter() {
            if renderable.layer >= 4 {
                self.push(RenderCacheEntry::new(
                    pos.x, pos.y, renderable.shape_type,
