    let h = tod / 60;
    let m = tod % 60;
    format!("Hora: {:02}:{:02}", h, m)
}
fn format_tick(tick: u64) -> String { format!("Tick: {}", tick) }
fn format_congestion(c: f32) -> String { format!("Traf: {:.0}%", c * 100.0) }
